class TNode:
    def __init__(self):
        self.children = {}
        self.end = False
class RootReplacer:
    def __init__(self, dictionary):
        self.root = TNode()
        for w in dictionary:
            self.insert(w)
    def insert(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                node.children[ch] = TNode()
            node = node.children[ch]
        node.end = True
    def replace_sentence(self, sentence: str) -> str:
        def shortest_root(word):
            node = self.root
            prefix = []
            for ch in word:
                if ch not in node.children:
                    return word
                node = node.children[ch]
                prefix.append(ch)
                if node.end:
                    return ''.join(prefix)
            return word
        parts = sentence.split()
        for i, w in enumerate(parts):
            parts[i] = shortest_root(w)
        return ' '.join(parts)

